import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { patientService, doctorService, appointmentService, billingService } from '../services/api';
import '../styles/auth.css';

const PatientDashboard = () => {
    const navigate = useNavigate();
    const [activeMenu, setActiveMenu] = useState('overview');
    const [patientProfile, setPatientProfile] = useState(null);
    const [appointments, setAppointments] = useState([]);
    const [doctors, setDoctors] = useState([]);
    const [billings, setBillings] = useState([]);
    const [loading, setLoading] = useState(false);
    const [user, setUser] = useState(null);
    const [showBookingForm, setShowBookingForm] = useState(false);
    const [selectedDoctor, setSelectedDoctor] = useState(null);
    const [bookingData, setBookingData] = useState({ date: '', time: '', reason: '' });

    useEffect(() => {
        const userData = JSON.parse(localStorage.getItem('user') || '{}');
        setUser(userData);
        loadDashboardData();
    }, []);

    const loadDashboardData = async () => {
        setLoading(true);
        try {
            const [profileRes, aptsRes, docsRes, billRes] = await Promise.all([
                patientService.getMyProfile().catch(() => ({ data: {} })),
                appointmentService.getAppointments().catch(() => ({ data: { results: [] } })),
                doctorService.getDoctors().catch(() => ({ data: { results: [] } })),
                billingService.getBillings().catch(() => ({ data: { results: [] } }))
            ]);
            setPatientProfile(profileRes?.data);
            setAppointments(aptsRes?.data?.results || aptsRes?.data || []);
            setDoctors(docsRes?.data?.results || docsRes?.data || []);
            setBillings(billRes?.data?.results || billRes?.data || []);
        } catch (error) {
            console.error('Error loading data:', error);
        } finally {
            setLoading(false);
        }
    };

