                    React.createElement(
                        'tbody',
                        null,
                        appointments.length === 0 ? React.createElement('tr', null, React.createElement('td', { colSpan: 5, style: { padding: '20px', textAlign: 'center', color: '#7f8c8d' } }, 'No appointments booked')) :
