                        null,
                        React.createElement('tr', { style: { backgroundColor: '#ecf0f1' } },
                            React.createElement('th', { style: { padding: '10px', textAlign: 'left', borderBottom: '1px solid #bdc3c7' } }, 'Appointment'),
                            React.createElement('th', { style: { padding: '10px', textAlign: 'left', borderBottom: '1px solid #bdc3c7' } }, 'Amount'),
